import{_ as s,H as e,f as n,i as p}from"./chunks/framework.BHvCMIhP.js";const u=JSON.parse('{"title":"域名是什么:注册商,注册局,DNS 托管的区别","description":"","frontmatter":{},"headers":[],"relativePath":"../cloudBasicsLearning/02-域名是什么.md","filePath":"../cloudBasicsLearning/02-域名是什么.md","lastUpdated":1779015580000}'),l={name:"../cloudBasicsLearning/02-域名是什么.md"};function i(t,a,o,c,d,r){return e(),n("div",null,[...a[0]||(a[0]=[p(`<h1 id="域名是什么-注册商-注册局-dns-托管的区别" tabindex="-1">域名是什么:注册商,注册局,DNS 托管的区别 <a class="header-anchor" href="#域名是什么-注册商-注册局-dns-托管的区别" aria-label="Permalink to &quot;域名是什么:注册商,注册局,DNS 托管的区别&quot;">​</a></h1><h2 id="一句话解释" tabindex="-1">一句话解释 <a class="header-anchor" href="#一句话解释" aria-label="Permalink to &quot;一句话解释&quot;">​</a></h2><p>域名就是给 IP 地址起的可读名字,比如 <code>example.com</code> 比 <code>203.0.113.10</code> 更容易记.</p><p>但独立开发者最容易踩坑的地方是:域名不是买完就自动能访问网站.买域名,管理域名归属,配置 DNS 解析,部署网站,是几件不同的事.</p><p>你可以把它理解成一个门牌系统:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>域名 = 门牌号,例如 example.com</span></span>
<span class="line"><span>IP = 真正的房子地址,例如 203.0.113.10</span></span>
<span class="line"><span>DNS = 查询门牌号对应房子地址的系统</span></span>
<span class="line"><span>网站服务器 = 房子本身</span></span></code></pre></div><p>用户在浏览器里输入 <code>example.com</code>,浏览器不会因为你买了这个域名就知道服务器在哪里.它还要通过 DNS 查到对应 IP,再去访问你的服务器或 CDN.</p><p>这里有三个容易混淆的角色:</p><ul><li>注册局:负责某个顶级域名的总账本,例如 <code>.com</code> 背后有对应的注册局.</li><li>注册商:卖域名给你的平台,例如你在哪里买,续费,改联系人.</li><li>DNS 托管商:真正保存 <code>example.com -&gt; 某个 IP</code> 这类解析记录的平台.</li></ul><p>很多云平台既能卖域名,也能做 DNS,还可能做网站托管,所以界面上看起来像一个东西.但从系统上看,它们是三层.</p><h2 id="放在系统哪里" tabindex="-1">放在系统哪里 <a class="header-anchor" href="#放在系统哪里" aria-label="Permalink to &quot;放在系统哪里&quot;">​</a></h2><p>域名处在用户访问链路的最入口.</p><p>一次最普通的网站访问大概是这样:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户输入域名</span></span>
<span class="line"><span>  -&gt; 浏览器询问 DNS:这个域名对应哪里</span></span>
<span class="line"><span>  -&gt; DNS 返回 IP 或 CDN 地址</span></span>
<span class="line"><span>  -&gt; 浏览器连接这个地址</span></span>
<span class="line"><span>  -&gt; 发起 HTTP / HTTPS 请求</span></span>
<span class="line"><span>  -&gt; 网站服务器返回页面</span></span></code></pre></div><p>域名本身不处理请求,不保存网页,也不让网站变快.它只是让用户可以用一个稳定的名字找到你的系统.</p><p>真实场景里,你可能会遇到这种情况:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>你在 A 平台买了 example.com</span></span>
<span class="line"><span>你在 B 平台部署了网站</span></span>
<span class="line"><span>你想用 C 平台的 CDN</span></span>
<span class="line"><span>你在 D 平台管理邮箱</span></span></code></pre></div><p>这完全正常.一个域名可以同时关联很多服务:</p><ul><li><code>example.com</code> 指向官网</li><li><code>www.example.com</code> 指向前端托管平台</li><li><code>api.example.com</code> 指向后端 API</li><li><code>admin.example.com</code> 指向管理后台</li><li><code>mx</code> 记录指向邮件服务</li></ul><p>所以域名不是一个网站,而是一个入口命名空间.小团队越早理解这一点,后面拆前端,后端,CDN,邮箱,监控时越不容易乱.</p><h2 id="常见套餐和使用限制" tabindex="-1">常见套餐和使用限制 <a class="header-anchor" href="#常见套餐和使用限制" aria-label="Permalink to &quot;常见套餐和使用限制&quot;">​</a></h2><p>域名不像服务器那样按 CPU,内存计费,它主要有这些限制和成本点.</p><h3 id="_1-注册和续费" tabindex="-1">1. 注册和续费 <a class="header-anchor" href="#_1-注册和续费" aria-label="Permalink to &quot;1. 注册和续费&quot;">​</a></h3><p>域名通常按年注册.第一年可能很便宜,续费可能变贵.很多新手只看首年价格,没有看续费价格,转出规则和隐私保护费用.</p><p>更麻烦的是忘记续费.域名过期后,网站,邮箱,登录回调,支付回调都可能一起出问题.对于一个 SaaS 来说,域名过期不是小故障,而是入口直接消失.</p><h3 id="_2-所有权和账号安全" tabindex="-1">2. 所有权和账号安全 <a class="header-anchor" href="#_2-所有权和账号安全" aria-label="Permalink to &quot;2. 所有权和账号安全&quot;">​</a></h3><p>域名归谁,取决于注册商账号和域名联系人信息.小团队常见错误是用创始人的个人邮箱注册域名,没有 MFA,没有共享应急流程.</p><p>一旦这个账号丢了,别人不需要攻破你的服务器,只要改掉 DNS,就能让用户访问到错误的地址.</p><h3 id="_3-dns-托管不等于域名注册" tabindex="-1">3. DNS 托管不等于域名注册 <a class="header-anchor" href="#_3-dns-托管不等于域名注册" aria-label="Permalink to &quot;3. DNS 托管不等于域名注册&quot;">​</a></h3><p>你可以在阿里云买域名,但把 DNS 托管到 Cloudflare.也可以在 Namecheap 买域名,但用 AWS Route 53 做权威 DNS.</p><p>真正决定 DNS 查询去哪里的是 NS 记录.也就是说,注册商那里记录的 nameserver 指向谁,全世界的 DNS 系统就会去问谁.</p><p>一个典型事故是:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>你在注册商 A 买了域名</span></span>
<span class="line"><span>你把 NS 改到了 Cloudflare</span></span>
<span class="line"><span>你却还在注册商 A 的 DNS 页面添加 A 记录</span></span>
<span class="line"><span></span></span>
<span class="line"><span>结果:</span></span>
<span class="line"><span>全世界都去问 Cloudflare</span></span>
<span class="line"><span>注册商 A 里的 A 记录没人看</span></span>
<span class="line"><span>网站一直打不开</span></span></code></pre></div><p>这不是 DNS &quot;没生效&quot;,而是你在错误的 DNS 托管商里改记录.</p><h3 id="_4-域名实名认证和地区规则" tabindex="-1">4. 域名实名认证和地区规则 <a class="header-anchor" href="#_4-域名实名认证和地区规则" aria-label="Permalink to &quot;4. 域名实名认证和地区规则&quot;">​</a></h3><p>有些地区的域名或云服务要求实名认证,备案,用途审核.这里不展开政策细节,但要记住:域名注册成功,不代表任何地区都能立刻稳定访问.</p><p>如果你的网站主要服务中国大陆用户,还要额外考虑备案,境内 CDN,境内云厂商接入规则.如果主要服务海外用户,则更关注全球 DNS,CDN,证书和隐私保护.</p><h2 id="小团队建议" tabindex="-1">小团队建议 <a class="header-anchor" href="#小团队建议" aria-label="Permalink to &quot;小团队建议&quot;">​</a></h2><p>域名是小团队最不该省心到完全不管的资产.</p><p>最低限度建议:</p><ul><li>用团队可控邮箱注册域名,不要只绑个人邮箱.</li><li>注册商账号开启 MFA.</li><li>开启自动续费,并在日历里设置续费提醒.</li><li>记录域名注册商,DNS 托管商,证书管理位置.</li><li>不要频繁更换 NS,除非你明确知道当前权威 DNS 在哪里.</li><li>上线前用 <code>dig NS example.com</code> 或在线 DNS 工具确认权威 DNS 指向.</li></ul><p>什么时候免费或基础方案够用?</p><p>如果你只是做一个个人网站,产品落地页,小型 SaaS,普通域名注册商加一个稳定的 DNS 托管服务通常就够了.你不需要一开始就买昂贵的企业 DNS.</p><p>什么时候该升级?</p><p>当域名承载生产业务,登录,支付,客户邮箱,API 回调时,就要把它当核心资产管理.此时更重要的是账号权限,审计,DNS 变更流程,备份联系人,而不是多买几个花哨后缀.</p><p>一个很实用的做法是:主域名用于正式业务,测试和临时项目尽量用子域名.不要为每个小实验都买一个新域名,否则管理和续费会变成长期负担.</p><h2 id="一句话总结" tabindex="-1">一句话总结 <a class="header-anchor" href="#一句话总结" aria-label="Permalink to &quot;一句话总结&quot;">​</a></h2><p>域名不是网站本身,而是用户进入你系统的入口名字;买域名,DNS 托管,服务器部署是三件事,小团队必须知道自己每一层放在哪里.</p>`,48)])])}const m=s(l,[["render",i]]);export{u as __pageData,m as default};
